import React, { useState, useEffect } from 'react';
import fishData from './FishData.json';

export default function KnowledgePage() {
    const [fishes, setFishes] = useState([]);
    const [expandedFishIds, setExpandedFishIds] = useState([]);

    useEffect(() => {
        setFishes(fishData.freshwater_fish_vietnam.slice(0, 4)); // Limit to 4 fish
    }, []);

    const toggleFishInfo = (id) => {
        setExpandedFishIds((prev) =>
            prev.includes(id) ? prev.filter((fid) => fid !== id) : [...prev, id]
        );
    };

    return (
        <div className="main-content p-6 bg-gray-100 min-h-screen flex flex-col items-center">
            <h1 className="text-3xl font-bold text-center mb-8 text-blue-800">
                Kiến thức về các loài cá nước ngọt Việt Nam
            </h1>
            <div className="flex flex-col gap-4 w-full max-w-lg">
                {fishes.map((fish) => {
                    const isExpanded = expandedFishIds.includes(fish.id);
                    return (
                        <div
                            key={fish.id}
                            className="bg-white rounded-xl shadow-lg p-4 flex flex-col justify-between h-40 transition-all duration-300 hover:shadow-xl"
                        >
                            {!isExpanded ? (
                                <div className="flex flex-col items-center justify-center h-full">
                                    <h2 className="text-lg font-semibold text-blue-600 text-center">
                                        {fish.name}
                                    </h2>
                                </div>
                            ) : (
                                <div className="text-xs text-gray-600 space-y-1 overflow-y-auto flex-grow pr-2">
                                    <p>
                                        <span className="font-medium">Đặc điểm:</span>{' '}
                                        {fish.characteristics.appearance}
                                    </p>
                                    <p>
                                        <span className="font-medium">Kích cỡ:</span>{' '}
                                        {fish.characteristics.size}
                                    </p>
                                    <p>
                                        <span className="font-medium">Tập tính:</span>{' '}
                                        {fish.behavior}
                                    </p>
                                    <p>
                                        <span className="font-medium">Mồi yêu thích:</span>{' '}
                                        {fish.favorite_bait}
                                    </p>
                                    <p>
                                        <span className="font-medium">Thông tin:</span>{' '}
                                        {fish.info}
                                    </p>
                                </div>
                            )}
                            <button
                                onClick={() => toggleFishInfo(fish.id)}
                                className="mt-2 px-3 py-1 bg-blue-500 text-white text-sm rounded-md hover:bg-blue-600 transition self-center"
                            >
                                Infor
                            </button>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}
